#include <iostream>      // Для ввода и вывода данных
#include <fstream>       // Для работы с файлами
#include <vector>        // Для использования контейнера vector
#include <algorithm>     // Для алгоритмов transform и copy
#include <functional>    // Для bind и placeholders
#include <string>        // Для работы со строками
#include <iterator>      // Для итераторов потоков istream_iterator

using namespace std;     
using namespace std::placeholders;

/**
 * @brief Структура, описывающая точку с двумя координатами и строковой меткой.
 *
 * @details
 * Структура point хранит:
 * - координату x;
 * - координату y;
 * - строковую метку s.
 *
 * Объекты данной структуры используются как элементы векторов V1 и V2.
 * Для структуры перегружены операторы ввода и вывода, а также реализован
 * метод умножения координат точки на целое число.
 */
struct point {
    int x;          
    int y;          
    std::string s;  

    /**
     * @brief Умножает координаты точки на заданное целое число.
     *
     * @param k Целочисленный множитель, на который умножаются координаты x и y.
     *
     * @return Новый объект point, у которого координаты x и y умножены на k,
     * а строковая метка s сохранена без изменений.
     *
     * @details
     * Метод не изменяет текущий объект, так как объявлен как const.
     * Вместо этого создается новый объект result, в который записывается
     * результат преобразования.
     */
    point mult(const int k) const;
};

/**
 * @brief Функциональный объект для сложения двух объектов типа point.
 *
 * @details
 * Функтор point_plus перегружает оператор круглых скобок operator().
 * Это позволяет использовать объект структуры как функцию.
 *
 * При сложении:
 * - координаты x складываются;
 * - координаты y складываются;
 * - строки s объединяются с помощью конкатенации.
 */
struct point_plus {
    /**
     * @brief Складывает две точки.
     *
     * @param a Первая точка.
     * @param b Вторая точка.
     *
     * @return Новый объект point, содержащий результат сложения точек a и b.
     *
     * @details
     * Результирующая точка формируется по правилу:
     * result.x = a.x + b.x;
     * result.y = a.y + b.y;
     * result.s = a.s + b.s.
     */
    point operator()(const point& a, const point& b) const;
};

/**
 * @brief Перегруженный оператор ввода для структуры point.
 *
 * @param is Входной поток, из которого считываются данные.
 * @param p Объект point, в который записываются считанные значения.
 *
 * @return Ссылка на входной поток is.
 *
 * @details
 * Оператор считывает данные в следующем порядке:
 * сначала координата x, затем координата y, затем строковая метка s.
 *
 * Пример строки во входном файле:
 * 2 5 A
 */
std::istream& operator>>(std::istream& is, point& p);

/**
 * @brief Перегруженный оператор вывода для структуры point.
 *
 * @param os Выходной поток, в который выводятся данные.
 * @param p Объект point, который необходимо вывести.
 *
 * @return Ссылка на выходной поток os.
 *
 * @details
 * Оператор выводит точку в формате:
 * x y s
 */
std::ostream& operator<<(std::ostream& os, const point& p);

/**
 * @brief Считывает точки из файла.
 *
 * @param filename Имя файла, из которого необходимо считать данные.
 *
 * @return Вектор объектов point, прочитанных из файла.
 *
 * @details
 * Функция открывает файл, проверяет успешность открытия,
 * затем считывает все точки с помощью потоковых итераторов.
 *
 * Если файл не удалось открыть, функция выводит сообщение об ошибке
 * и возвращает пустой вектор.
 */
vector<point> readPointsFromFile(const string& filename);

/**
 * @brief Обрабатывает два вектора точек.
 *
 * @param V1 Первый вектор точек. Он изменяется в процессе работы функции.
 * @param V2 Второй вектор точек. Он используется только для чтения.
 * @param K Целочисленный множитель для преобразования точек из V1.
 *
 * @details
 * Для каждого элемента выполняется преобразование:
 *
 * V1[i] = point_plus()(V1[i].mult(K), V2[i])
 *
 * То есть сначала точка из V1 умножается на K,
 * затем к полученному результату прибавляется соответствующая точка из V2.
 */
void processPoints(vector<point>& V1, const vector<point>& V2, const int K);

/**
 * @brief Выводит результат обработки вектора точек на экран.
 *
 * @param V1 Вектор обработанных точек.
 *
 * @details
 * Функция выводит все элементы вектора V1 в удобном формате,
 * а также показывает общее количество обработанных точек.
 */
void displayResults(const vector<point>& V1);

/**
 * @brief Главная функция программы.
 *
 * @return Код завершения программы:
 * - 0 — программа выполнена успешно;
 * - 1 — произошла ошибка.
 *
 * @details
 * Главная функция выполняет следующий алгоритм:
 * 1. Запрашивает у пользователя число K.
 * 2. Запрашивает имена двух файлов.
 * 3. Считывает точки из первого файла в вектор V1.
 * 4. Считывает точки из второго файла в вектор V2.
 * 5. Проверяет, что оба файла содержат одинаковое количество элементов.
 * 6. Выполняет обработку векторов.
 * 7. Выводит результат на экран.
 */
int main() {
    int K = 0;           
    string name1;        
    string name2;        

    cout << "Введите число K: "; 
    cin >> K;                    

    cout << "Введите имя первого файла: "; 
    cin >> name1;                          

    cout << "Введите имя второго файла: "; 
    cin >> name2;                          
    
    vector<point> V1 = readPointsFromFile(name1);

    if (V1.empty() && !ifstream(name1).is_open()) {
        return 1;
    }
    
    vector<point> V2 = readPointsFromFile(name2);

    if (V2.empty() && !ifstream(name2).is_open()) {
        return 1;
    }
    
    if (V1.size() != V2.size()) {
        cerr << "Ошибка: файлы содержат разное количество элементов!" << endl;
        cerr << "В первом файле: " << V1.size() << " элементов" << endl;
        cerr << "Во втором файле: " << V2.size() << " элементов" << endl;
        return 1;
    }
    
    processPoints(V1, V2, K);
    
    displayResults(V1);
    
    return 0;
}

/**
 * @brief Умножает координаты точки на целое число.
 *
 * @param k Целое число, на которое умножаются координаты точки.
 *
 * @return Новый объект point с измененными координатами.
 *
 * @details
 * Метод создает новый объект result.
 * Координаты x и y умножаются на k.
 * Строковая метка s копируется без изменений.
 */
point point::mult(int k) const {
    point result;
    result.x = k * this->x;
    result.y = k * this->y;
    result.s = this->s;
    return result;
}

/**
 * @brief Выполняет сложение двух точек.
 *
 * @param a Первая точка.
 * @param b Вторая точка.
 *
 * @return Новый объект point, полученный сложением a и b.
 *
 * @details
 * Функтор используется в алгоритме transform.
 * Он позволяет передать операцию сложения точек как функциональный объект.
 */
point point_plus::operator()(const point& a, const point& b) const {
    point result;
    result.x = a.x + b.x;
    result.y = a.y + b.y;
    result.s = a.s + b.s;
    return result;
}

/**
 * @brief Считывает объект point из входного потока.
 *
 * @param is Входной поток.
 * @param p Объект point, в который записываются считанные данные.
 *
 * @return Ссылка на входной поток.
 *
 * @details
 * Данные должны быть представлены в формате:
 * x y s
 *
 * Например:
 * 1 4 text
 */
std::istream& operator>>(std::istream& is, point& p) {
    is >> p.x >> p.y >> p.s;
    return is;
}

/**
 * @brief Выводит объект point в выходной поток.
 *
 * @param os Выходной поток.
 * @param p Объект point, который необходимо вывести.
 *
 * @return Ссылка на выходной поток.
 *
 * @details
 * Формат вывода:
 * x y s
 */
std::ostream& operator<<(std::ostream& os, const point& p) {
    os << p.x << " " << p.y << " " << p.s;
    return os;
}

/**
 * @brief Читает набор точек из файла.
 *
 * @param filename Имя файла для чтения.
 *
 * @return Вектор точек, считанных из файла.
 *
 * @details
 * Функция открывает файл с указанным именем.
 * Если файл открыт успешно, чтение выполняется через istream_iterator.
 * Каждый считанный объект добавляется в конец вектора points.
 *
 * Если файл не удалось открыть, выводится сообщение об ошибке,
 * а функция возвращает пустой вектор.
 */
vector<point> readPointsFromFile(const string& filename) {
    vector<point> points;

    ifstream file(filename);
    
    if (!file.is_open()) {
        cerr << "Ошибка: не удалось открыть файл " << filename << endl;
        return points;
    }
    
    copy(istream_iterator<point>(file),
         istream_iterator<point>(),
         back_inserter(points));
    
    file.close();
    return points;
}

/**
 * @brief Выполняет преобразование элементов вектора V1.
 *
 * @param V1 Первый вектор точек, элементы которого будут изменены.
 * @param V2 Второй вектор точек, элементы которого используются при сложении.
 * @param K Множитель для координат точек из V1.
 *
 * @details
 * Для каждого индекса i выполняется операция:
 *
 * V1[i] = V1[i].mult(K) + V2[i]
 *
 * Реализация выполнена через стандартный алгоритм transform,
 * функтор point_plus и функцию bind.
 *
 * В результате:
 * - координаты точки из V1 сначала умножаются на K;
 * - затем к ним прибавляются координаты соответствующей точки из V2;
 * - строковые метки объединяются.
 */
void processPoints(vector<point>& V1, const vector<point>& V2, const int K) {
    transform(V1.begin(),
              V1.end(),
              V2.begin(),
              V1.begin(),
        bind(point_plus(),
            bind(&point::mult, _1, K),
            _2)
    );
}

/**
 * @brief Выводит обработанный вектор точек на экран.
 *
 * @param V1 Вектор точек, который необходимо вывести.
 *
 * @details
 * Функция выводит заголовок, затем последовательно выводит
 * все элементы вектора V1 с их порядковыми номерами.
 * В конце выводится общее количество обработанных точек.
 */
void displayResults(const vector<point>& V1) {
    cout << "\n========================================" << endl;
    cout << "Результат преобразования вектора V1:" << endl;
    cout << "========================================\n" << endl;
    
    for (size_t i = 0; i < V1.size(); ++i) {
        cout << "Точка " << i + 1 << ": " << V1[i] << endl;
    }
    
    cout << "\n========================================" << endl;
    cout << "Всего обработано точек: " << V1.size() << endl;
    cout << "========================================" << endl;
}
